solution_code:
#include <iostream>

int main()
{
    int arr[20]{};
    int n{};
    std::cin >> n;

    for (int k{ 0 }; k < n; ++k)
        std::cin >> arr[k];

    int* begin{ arr };
    int* end{ arr + n };

    for (int* p{ end }; p != begin; )
    {
        --p;
        std::cout << *p << ' ';
    }
    std::cout << '\n';

    return 0;
}
